     1→/**
     2→ * 管理画面用型定義
     3→ * Sprint1 管理画面開発
     4→ */
     5→
     6→/**
     7→ * 管理者認証情報
     8→ */
     9→export interface AdminUser {
    10→  authenticated: boolean;
    11→  exp: number;
    12→}
    13→
    14→/**
    15→ * アップロードステータス
    16→ */
    17→export type UploadStatus = 'uploading' | 'completed' | 'failed';
    18→
    19→/**
    20→ * File Search Store ファイルメタデータ
    21→ */
    22→export interface FileMetadata {
    23→  file_id: string;
    24→  display_name: string;
    25→  source_type: 'web' | 'qa';
    26→  uploaded_at: string;
    27→  locale?: string;
    28→  category?: string;
