    25→
    26→/**
    27→ * Search files using Gemini File Search API and return top results
    28→ *
    29→ * @param query - User search query
    30→ * @param options - Search options (timeout, numResults)
    31→ * @returns FileSearchResponse with results or fallback context
    32→ */
    33→export async function searchFiles(
    34→  query: string,
    35→  options: SearchOptions = {}
    36→): Promise<FileSearchResponse> {
    37→  logger.info({ query }, '[File Search] Starting search');
    38→
    39→  const { timeout = 30000, numResults = 3 } = options;
    40→
    41→  try {
    42→    const apiKey = getGeminiApiKey();
    43→
    44→    if (!apiKey) {
    45→      // Issue #109: Use ApiError for better error handling
    46→      logger.error('[File Search] Gemini API key is not set');
    47→      // Return fallback instead of throwing - maintains user experience
    48→      return {
    49→        success: true,
    50→        results: getFallbackContext(),
    51→      };
    52→    }
    53→
    54→    // Load manifest
    55→    const manifest = await loadManifest();
    56→
    57→    // Timeout handling with Promise.race
    58→    const searchPromise = performFileSearchStoreSearch(apiKey, query, numResults, manifest);
    59→    const timeoutPromise = new Promise<FileSearchResult[]>((_, reject) =>
    60→      setTimeout(() => reject(ApiError.serviceUnavailable('Search timeout')), timeout)
    61→    );
    62→
    63→    const results = await Promise.race([searchPromise, timeoutPromise]);
    64→
    65→    return {
    66→      success: true,
    67→      results: results.length > 0 ? results : getFallbackContext(),
    68→    };
    69→  } catch (error) {
    70→    // Issue #109: Structured error logging with ApiError
    71→    if (error instanceof ApiError) {
    72→      logger.warn(
    73→        { code: error.code, message: error.message },
    74→        '[File Search] Expected error occurred'
    75→      );
    76→    } else {
    77→      logger.error({ error }, '[File Search] Unexpected error');
    78→    }
    79→
    80→    // Always return fallback context to maintain user experience
    81→    return {
    82→      success: true,
    83→      results: getFallbackContext(),
    84→    };
    85→  }
    86→}
